#include "biblia.h"

void Biblia::Carregar1Tessalonicenses(Biblia* b) {
    b->dados[TESSALONICENSES1].nome = wxT("1 Tessalonicenses");

    b->dados[TESSALONICENSES1].capitulos[1].versos[1] = wxT("Paulo, Silvano e Timóteo, à igreja dos tessalonicenses, em Deus Pai e no Senhor Jesus Cristo: Graça e paz vos sejam dadas.");
    b->dados[TESSALONICENSES1].capitulos[1].versos[2] = wxT("Sempre damos graças a Deus por vós todos, fazendo menção de vós em nossas orações,");
    b->dados[TESSALONICENSES1].capitulos[1].versos[3] = wxT("lembrando-nos sem cessar da vossa obra de fé, do vosso trabalho de amor e da vossa firmeza de esperança em nosso Senhor Jesus Cristo, diante de nosso Deus e Pai,");
    b->dados[TESSALONICENSES1].capitulos[1].versos[4] = wxT("conhecendo, irmãos, amados de Deus, a vossa eleição;");
    b->dados[TESSALONICENSES1].capitulos[1].versos[5] = wxT("porque o nosso evangelho não foi a vós somente em palavras, mas também em poder, e no Espírito Santo e em plena convicção, como bem sabeis quais fomos entre vós por amor de vós.");
    b->dados[TESSALONICENSES1].capitulos[1].versos[6] = wxT("E vós vos tornastes imitadores nossos e do Senhor, tendo recebido a palavra em muita tribulação, com gozo do Espírito Santo.");
    b->dados[TESSALONICENSES1].capitulos[1].versos[7] = wxT("De sorte que vos tornastes modelo para todos os crentes na Macedônia e na Acaia.");
    b->dados[TESSALONICENSES1].capitulos[1].versos[8] = wxT("Porque, partindo de vós fez-se ouvir a palavra do Senhor, não somente na Macedônia e na Acaia, mas também em todos os lugares a vossa fé para com Deus se divulgou, de tal maneira que não temos necessidade de falar coisa alguma;");
    b->dados[TESSALONICENSES1].capitulos[1].versos[9] = wxT("porque eles mesmos anunciam de nós qual a entrada que tivemos entre vós, e como vos convertestes dos ídolos a Deus, para servirdes ao Deus vivo e verdadeiro,");
    b->dados[TESSALONICENSES1].capitulos[1].versos[10] = wxT("e esperardes dos céus a seu Filho, a quem ele ressuscitou dentre os mortos, a saber, Jesus, que nos livra da ira vindoura.");

    b->dados[TESSALONICENSES1].capitulos[2].versos[1] = wxT("Porque vós mesmos sabeis, irmãos, que a nossa entrada entre vós não foi vã;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[2] = wxT("mas, havendo anteriormente padecido e sido maltratados em Filipos, como sabeis, tivemos a confiança em nosso Deus para vos falar o evangelho de Deus em meio de grande combate.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[3] = wxT("Porque a nossa exortação não procede de erro, nem de imundícia, nem é feita com dolo;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[4] = wxT("mas, assim como fomos aprovados por Deus para que o evangelho nos fosse confiado, assim falamos, não para agradar aos homens, mas a Deus, que prova os nossos corações.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[5] = wxT("Pois, nunca usamos de palavras lisonjeiras, como sabeis, nem agimos com intuitos gananciosos. Deus é testemunha,");
    b->dados[TESSALONICENSES1].capitulos[2].versos[6] = wxT("nem buscamos glória de homens, quer de vós, quer de outros, embora pudéssemos, como apóstolos de Cristo, ser-vos pesados;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[7] = wxT("antes nos apresentamos brandos entre vós, qual ama que acaricia seus próprios filhos.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[8] = wxT("Assim nós, sendo-vos tão afeiçoados, de boa vontade desejávamos comunicar-vos não somente o evangelho de Deus, mas ainda as nossas próprias almas; porquanto vos tornastes muito amados de nós.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[9] = wxT("Porque vos lembrais, irmãos, do nosso labor e fadiga; pois, trabalhando noite e dia, para não sermos pesados a nenhum de vós, vos pregamos o evangelho de Deus.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[10] = wxT("Vós e Deus sois testemunhas de quão santa e irrepreensivelmente nos portamos para convosco que credes;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[11] = wxT("assim como sabeis de que modo vos tratávamos a cada um de vós, como um pai a seus filhos,");
    b->dados[TESSALONICENSES1].capitulos[2].versos[12] = wxT("exortando-vos e consolando-vos, e instando que andásseis de um modo digno de Deus, o qual vos chama ao seu reino e glória.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[13] = wxT("Por isso nós também, sem cessar, damos graças a Deus, porquanto vós, havendo recebido a palavra de Deus que de nós ouvistes, a recebestes, não como palavra de homens, mas {segundo ela é na verdade} como palavra de Deus, a qual também opera em vós que credes.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[14] = wxT("Pois vós, irmãos, vos haveis feito imitadores das igrejas de Deus em Cristo Jesus que estão na Judéia; porque também padecestes de vossos próprios concidadãos o mesmo que elas padeceram dos judeus;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[15] = wxT("os quais mataram ao Senhor Jesus, bem como aos profetas, e a nós nos perseguiram, e não agradam a Deus, e são contrários a todos os homens,");
    b->dados[TESSALONICENSES1].capitulos[2].versos[16] = wxT("e nos impedem de falar aos gentios para que sejam salvos; de modo que enchem sempre a medida de seus pecados; mas a ira caiu sobre eles afinal.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[17] = wxT("Nós, porém, irmãos, sendo privados de vós por algum tempo, de vista, mas não de coração, tanto mais procuramos com grande desejo ver o vosso rosto;");
    b->dados[TESSALONICENSES1].capitulos[2].versos[18] = wxT("pelo que quisemos ir ter convosco, pelo menos eu, Paulo, não somente uma vez, mas duas, e Satanás nos impediu.");
    b->dados[TESSALONICENSES1].capitulos[2].versos[19] = wxT("Porque, qual é a nossa esperança, ou gozo, ou coroa de glória, diante de nosso Senhor Jesus na sua vinda? Porventura não o sois vós?");
    b->dados[TESSALONICENSES1].capitulos[2].versos[20] = wxT("Na verdade vós sois a nossa glória e o nosso gozo.");

    b->dados[TESSALONICENSES1].capitulos[3].versos[1] = wxT("Pelo que, não podendo mais suportar o cuidado por vós, achamos por bem ficar sozinhos em Atenas,");
    b->dados[TESSALONICENSES1].capitulos[3].versos[2] = wxT("e enviamos Timóteo, nosso irmão, e ministro de Deus no evangelho de Cristo, para vos fortalecer e vos exortar acerca da vossa fé;");
    b->dados[TESSALONICENSES1].capitulos[3].versos[3] = wxT("para que ninguém seja abalado por estas tribulações; porque vós mesmo sabeis que para isto fomos destinados;");
    b->dados[TESSALONICENSES1].capitulos[3].versos[4] = wxT("pois, quando estávamos ainda convosco, de antemão vos declarávamos que havíamos de padecer tribulações, como sucedeu, e vós o sabeis.");
    b->dados[TESSALONICENSES1].capitulos[3].versos[5] = wxT("Por isso também, não podendo eu esperar mais, mandei saber da vossa fé, receando que o tentador vos tivesse tentado, e o nosso trabalho se houvesse tornado inútil.");
    b->dados[TESSALONICENSES1].capitulos[3].versos[6] = wxT("Mas agora que Timóteo acaba de regressar do vosso meio, trazendo-nos boas notícias da vossa fé e do vosso amor, dizendo que sempre nos tendes em afetuosa lembrança, anelando ver-nos assim como nós também a vós;");
    b->dados[TESSALONICENSES1].capitulos[3].versos[7] = wxT("por isso, irmãos, em toda a nossa necessidade e tribulação, ficamos consolados acerca de vós, pela vossa fé,");
    b->dados[TESSALONICENSES1].capitulos[3].versos[8] = wxT("porque agora vivemos, se estais firmes no Senhor.");
    b->dados[TESSALONICENSES1].capitulos[3].versos[9] = wxT("Pois, que ação de graças podemos render a Deus por vós, por todo o gozo com que nos regozijamos por vossa causa diante do nosso Deus,");
    b->dados[TESSALONICENSES1].capitulos[3].versos[10] = wxT("rogando incessantemente, de noite e de dia, para que possamos ver o vosso rosto e suprir o que falta à vossa fé?");
    b->dados[TESSALONICENSES1].capitulos[3].versos[11] = wxT("Ora, o próprio Deus e Pai nosso e o nosso Senhor Jesus nos abram o caminho até vós,");
    b->dados[TESSALONICENSES1].capitulos[3].versos[12] = wxT("e o Senhor vos faça crescer e abundar em amor uns para com os outros e para com todos, como também nós abundamos para convosco;");
    b->dados[TESSALONICENSES1].capitulos[3].versos[13] = wxT("para vos confirmar os corações, de sorte que sejam irrepreensíveis em santidade diante de nosso Deus e Pai, na vinda de nosso Senhor Jesus com todos os seus santos.");

    b->dados[TESSALONICENSES1].capitulos[4].versos[1] = wxT("Finalmente, irmãos, vos rogamos e exortamos no Senhor Jesus que, como aprendestes de nós de que maneira deveis andar e agradar a Deus, assim como estais fazendo, nisso mesmo abundeis cada vez mais.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[2] = wxT("Pois vós sabeis que preceitos vos temos dado pelo Senhor Jesus.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[3] = wxT("Porque esta é a vontade de Deus, a saber, a vossa santificação: que vos abstenhais da prostituição,");
    b->dados[TESSALONICENSES1].capitulos[4].versos[4] = wxT("que cada um de vós saiba possuir o seu vaso em santidade e honra,");
    b->dados[TESSALONICENSES1].capitulos[4].versos[5] = wxT("não na paixão da concupiscência, como os gentios que não conhecem a Deus;");
    b->dados[TESSALONICENSES1].capitulos[4].versos[6] = wxT("ninguém iluda ou defraude nisso a seu irmão, porque o Senhor é vingador de todas estas coisas, como também antes vo-lo dissemos e testificamos.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[7] = wxT("Porque Deus não nos chamou para a imundícia, mas para a santificação.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[8] = wxT("Portanto, quem rejeita isso não rejeita ao homem, mas sim a Deus, que vos dá o seu Espírito Santo.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[9] = wxT("Quanto, porém, ao amor fraternal, não necessitais de que se vos escreva, visto que vós mesmos sois instruídos por Deus a vos amardes uns aos outros;");
    b->dados[TESSALONICENSES1].capitulos[4].versos[10] = wxT("porque certamente já o fazeis para com todos os irmãos que estão por toda a Macedônia. Exortamo-vos, porém, irmãos, a que ainda nisto abundeis cada vez mais,");
    b->dados[TESSALONICENSES1].capitulos[4].versos[11] = wxT("e procureis viver quietos, tratar dos vossos próprios negócios, e trabalhar com vossas próprias mãos, como já vo-lo mandamos,");
    b->dados[TESSALONICENSES1].capitulos[4].versos[12] = wxT("a fim de que andeis dignamente para com os que estão de fora, e não tenhais necessidade de coisa alguma.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[13] = wxT("Não queremos, porém, irmãos, que sejais ignorantes acerca dos que já dormem, para que não vos entristeçais como os outros que não têm esperança.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[14] = wxT("Porque, se cremos que Jesus morreu e ressurgiu, assim também aos que dormem, Deus, mediante Jesus, os tornará a trazer juntamente com ele.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[15] = wxT("Dizemo-vos, pois, isto pela palavra do Senhor: que nós, os que ficarmos vivos para a vinda do Senhor, de modo algum precederemos os que já dormem.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[16] = wxT("Porque o Senhor mesmo descerá do céu com grande brado, à voz do arcanjo, ao som da trombeta de Deus, e os que morreram em Cristo ressuscitarão primeiro.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[17] = wxT("Depois nós, os que ficarmos vivos seremos arrebatados juntamente com eles, nas nuvens, ao encontro do Senhor nos ares, e assim estaremos para sempre com o Senhor.");
    b->dados[TESSALONICENSES1].capitulos[4].versos[18] = wxT("Portanto, consolai-vos uns aos outros com estas palavras.");

    b->dados[TESSALONICENSES1].capitulos[5].versos[1] = wxT("Mas, irmãos, acerca dos tempos e das épocas não necessitais de que se vos escreva:");
    b->dados[TESSALONICENSES1].capitulos[5].versos[2] = wxT("porque vós mesmos sabeis perfeitamente que o dia do Senhor virá como vem o ladrão de noite;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[3] = wxT("pois quando estiverem dizendo: Paz e segurança! então lhes sobrevirá repentina destruição, como as dores de parto àquela que está grávida; e de modo nenhum escaparão.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[4] = wxT("Mas vós, irmãos, não estais em trevas, para que aquele dia, como ladrão, vos surpreenda;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[5] = wxT("porque todos vós sois filhos da luz e filhos do dia; nós não somos da noite nem das trevas;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[6] = wxT("não durmamos, pois, como os demais, antes vigiemos e sejamos sóbrios.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[7] = wxT("Porque os que dormem, dormem de noite, e os que se embriagam, embriagam-se de noite;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[8] = wxT("mas nós, porque somos do dia, sejamos sóbrios, vestindo-nos da couraça da fé e do amor, e tendo por capacete a esperança da salvação;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[9] = wxT("porque Deus não nos destinou para a ira, mas para alcançarmos a salvação por nosso Senhor Jesus Cristo,");
    b->dados[TESSALONICENSES1].capitulos[5].versos[10] = wxT("que morreu por nós, para que, quer vigiemos, quer durmamos, vivamos juntamente com ele.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[11] = wxT("Pelo que exortai-vos uns aos outros e edificai-vos uns aos outros, como na verdade o estais fazendo.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[12] = wxT("Ora, rogamo-vos, irmãos, que reconheçais os que trabalham entre vós, presidem sobre vós no Senhor e vos admoestam;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[13] = wxT("e que os tenhais em grande estima e amor, por causa da sua obras. Tende paz entre vós.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[14] = wxT("Exortamo-vos também, irmãos, a que admoesteis os insubordinados, consoleis os desanimados, ampareis os fracos e sejais longânimos para com todos.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[15] = wxT("Vede que ninguém dê a outrem mal por mal, mas segui sempre o bem, uns para com os outros, e para com todos.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[16] = wxT("Regozijai-vos sempre.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[17] = wxT("Orai sem cessar.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[18] = wxT("Em tudo dai graças; porque esta é a vontade de Deus em Cristo Jesus para convosco.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[19] = wxT("Não extingais o Espírito;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[20] = wxT("não desprezeis as profecias,");
    b->dados[TESSALONICENSES1].capitulos[5].versos[21] = wxT("mas ponde tudo à prova. Retende o que é bom;");
    b->dados[TESSALONICENSES1].capitulos[5].versos[22] = wxT("Abstende-vos de toda espécie de mal.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[23] = wxT("E o próprio Deus de paz vos santifique completamente; e o vosso espírito, e alma e corpo sejam plenamente conservados irrepreensíveis para a vinda de nosso Senhor Jesus Cristo.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[24] = wxT("Fiel é o que vos chama, e ele também o fará.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[25] = wxT("Irmãos, orai por nós.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[26] = wxT("Saudai a todos os irmãos com ósculo santo.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[27] = wxT("Pelo Senhor vos conjuro que esta epístola seja lida a todos os irmãos.");
    b->dados[TESSALONICENSES1].capitulos[5].versos[28] = wxT("A graça de nosso Senhor Jesus Cristo seja convosco.");

}
